var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......그렇습니까.","JPN":"……そうでしたか。","ENG":"I see.","TWN":"……是嗎。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"결국 리타와 대시는 귀환에 실패했군요.","JPN":"結局リタとダッシュは帰還に失敗したのですね。","ENG":"So Rita and Dash failed to return after all.","TWN":"最後，麗塔和黛西還是沒有回來現世嗎。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 소식을 전해 드려 유감입니다.","JPN":"このような知らせで残念です。","ENG":"I'm sorry you had to hear this.","TWN":"很遺憾，通知您這樣的消息。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그녀들에게서 채취한 이터니움은 폐기 판정을 받고 관리국에 회수된 상태입니다.","JPN":"彼女たちから採取したエタニウムは廃棄判定を受け、管理局に回収されています。","ENG":"The Eternium extracted from them has been marked for disposal and collected by the Administration.","TWN":"從她們身上採集的永恆之金因為不能使用只能廢棄，所以被管理局回收了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 드릴 수 있는 건...... 미니스트라와의 교전 후에 회수한 당신의 기억 회로뿐이겠군요.","JPN":"こちらから差し上げられるものは、ミニストラとの交戦後に回収したあなたの記憶回路のみです。","ENG":"All I can give you... is your memory unit recovered after the engagement with Ministra.","TWN":"我能交給您的……只有在跟潼恩交戰後所回收的與您有關的記憶迴路。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"괜찮습니다.","JPN":"心配無用です。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"저는 인간이 아닌 기계이므로, 유품을 통해 휘발된 감정을 재생하는 방법은 모릅니다.","JPN":"私は人間ではなく機械なので、遺品を通じて発生した感情を再生する方法はわかりません。","ENG":"I am a machine. Unlike humans, I do not know how to reminisce about others, based only on their belongings.","TWN":"我是機器不是人類，不懂如何透過遺物重新喚起失去的感情。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타가 쓰던 책상도, 대시가 쓰던 가계부도 현재 모두 처분한 상태입니다.","JPN":"リタが使っていたデスクも、ダッシュが書いていた家計簿もすべて処分しています。","ENG":"I've already disposed of Rita's desk and Dash's ledger.","TWN":"麗塔用過的書桌，黛西用過的帳簿現在都已經處理掉了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그렇군요.","JPN":"……そうでしたか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만, 그럼 어째서 그녀들에게서 나온 이터니움을 구매하겠다고 하신 거죠?","JPN":"では、どうして彼女たちから出てきたエタニウムを買うとおっしゃったのですか？","ENG":"Then why did you offer to purchase the Eternium from them?","TWN":"但是，您為什麼還說要購買她們的永恆之金呢？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"책임을 지기 위해서입니다.","JPN":"責任を取るためです。","ENG":"To bear responsibility.","TWN":"為了負責。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"계약서에 따르면 직원들의 안전 역시 대표인 저의 책임입니다.","JPN":"契約書によれば、職員たちの安全も代表である私の責任です。","ENG":"As their employer, I have a contractual obligation to ensure their safety.","TWN":"按照合約，職員的安全就是身為老闆的我所該背負的責任。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"저는 그 책임을 완수하지 못했습니다.","JPN":"私はその責任を果たすことができませんでした。","ENG":"And I failed to honor that obligation.","TWN":"我沒盡到那個責任。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그렇다면 최소한 뒷일은 잘 마무리해야겠죠.","JPN":"ならば少なくとも、後始末だけはしっかりやらなければならないでしょう。","ENG":"The least I can do is follow suit with due diligence.","TWN":"所以，至少要好好的處理後事。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"두 사람이 오기 전까지, 호라이즌 파이낸스는 인상적인 일처리로 유명했습니다, 휴먼.","JPN":"二人が来る前まで、ホライズン・ファイナンスは印象深い仕事ぶりで有名でした、ヒューマン。","ENG":"Before those two joined the company, Horizon Finance was notorious for its... intense business operations.","TWN":"在她們兩個來到我這之前，地平線金融可是以令人印象深刻的辦事方式而聞名的，人類。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"필요하다면 수금 과정에서 과격한 수단을 동원하기도 했죠.","JPN":"必要ならば集金の過程で過激な手段を伴うこともありました。","ENG":"I didn't hesitate to resort to more aggressive measures to ensure timely collection.","TWN":"在收款過程中，必要時也會動用一些特殊手段。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"하지만 그러기 위해서는 안정적인 동력원이 필요했습니다.","JPN":"しかし、そのためには安定した動力源が必要でした。","ENG":"But in order to do so, I needed a stable source of power.","TWN":"但為此需要穩定的動力源。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};